import { combineReducers, configureStore, Middleware } from '@reduxjs/toolkit'
import logger from 'redux-logger'
import { persistStore, persistReducer } from 'redux-persist'
import storage from 'redux-persist/lib/storage'

import { createReduxHistory, routerMiddleware, routerReducer } from './history'
import { isProduction } from '@common/constants/env'
import user from '@common/store/slices/user'
import login from '@common/store/login/login'
const persistConfig = {
  key: 'root', // 本地存储的根键名(localStorage中对应 key: persist:root)
  storage, // 存储引擎（storage(localStorage)/sessionStorage）
  whitelist: ['biaRecords', 'riskList', 'bcStrategy', 'riskCreationWizard'], // 仅持久化whitelist数据
  blacklist: ['user', 'router'], // 排除不需要持久化的状态(与whitelist互斥)
}

const rootReducer = combineReducers({
  user,
  login,
  router: routerReducer,
})

const persistedReducer = persistReducer(persistConfig, rootReducer)

const store = configureStore({
  reducer: persistedReducer,
  middleware: (getDefaultMiddleware) => {
    // redux file上传文件的数据是非序列号的 设置serializableCheck: false
    const middleware = getDefaultMiddleware({
      serializableCheck: false,
    }).concat(routerMiddleware)

    // 生产环境不需要加载
    if (!isProduction) {
      middleware.push(logger as Middleware)
    }

    return middleware
  },
})

export const history = createReduxHistory(store)
export const persistor = persistStore(store) //创建persistor（用于控制持久化过程，如状态恢复、刷新等）

export { store }

export type RootState = ReturnType<typeof store.getState>
export type AppDispatch = typeof store.dispatch

