import en from './en'

// 阿拉伯语
import ar from './arEG'
import { getLanguage } from '@common/utils/localStorage'

i18n.use(initReactI18next).init({
  resources: {
    en,
    ar,
  },
  // 将默认语言设置为从本地存取，否则英语
  lng: getLanguage() || 'en',
  // 当无法找到针对特定语言的翻译内容时，会回退到指定的默认语言
  fallbackLng: 'en',
  debug: false,
  react: {
    useSuspense: false,
  },

  /**
   *  这个属性定义了插值处理的选项。
   * 在国际化中，有时需要在翻译字符串中插入变量或表达式，这个选项可以控制如何处理这些插值。
   */
  interpolation: {
    // escapeValue: false 表示不对插值进行转义处理，允许其中包含 HTML 或其他特殊字符。
    escapeValue: false,
  },
})

export default i18n

import { HistoryRouter } from 'redux-first-history/rr6'
import { Route, Routes } from 'react-router-dom'
import type { RoutesType } from '@common/types/route'
import { history } from '@/store'

import routes from './routes'

function RouterContainer() {
  const RouteAuthFun = (routeList: RoutesType[]) => {
    return routeList.map((route) => {
      return (
        <Route key={route.path} path={route.path} element={route.element}>
          {route?.children && RouteAuthFun(route.children)}
        </Route>
      )
    })
  }

  return (
    <HistoryRouter history={history}>
      <Routes>{RouteAuthFun(routes)}</Routes>
    </HistoryRouter>
  )
}

export default RouterContainer

