import { LanguageEnum } from '@common/constants/language'
import {
  tokenStorageKey,
  languageStorageKey,
  redirectStorageKey,
} from '@common/constants/localStorageKey'

export const getToken = () => {
  return window.localStorage.getItem(tokenStorageKey)
}

export const setToken = (token: string) => {
  window.localStorage.setItem(tokenStorageKey, token)
}

export const removeToken = () => {
  window.localStorage.removeItem(tokenStorageKey)
}

export const getLanguage: () => LanguageEnum = () => {
  return (window.localStorage.getItem(languageStorageKey) ||
    LanguageEnum.EN) as LanguageEnum
}

export const setLanguage = (language: LanguageEnum) => {
  window.localStorage.setItem(languageStorageKey, language)
}

// 重定向存储url
export const setRedirectStorage = () => {
  // 统一跳转/页面,不记录最后一次的url
  let urlInfo = new URL(window.location.href)
  let url = urlInfo.origin + '/emergency-response'
  const value = encodeURIComponent(url)
  window.sessionStorage.setItem(redirectStorageKey, value)
  return value
}

export const getRedirectStorage = () => {
  let value = window.sessionStorage.getItem(redirectStorageKey) || '/'
  value = decodeURIComponent(value)
  removeRedirectStorage()
  return value
}

export const removeRedirectStorage = () => {
  window.sessionStorage.removeItem(redirectStorageKey)
}

export const redirectToLogin = () => {
  removeToken()
  window.location.replace(`/login?redirect=${setRedirectStorage()}`)
}

