  loading: false,
  roleInfo: {} as CurrentUserRoleInfo,
  userInfo: {} as CurrentUserInfo,
  orgList: [],
  userRoleMenuList: [],
  userRoleBtnMenuList: [],
  managementFrontUrl: '',
  employeeFrontUrl: '',
}

export interface ChangeTokenAction {
  type: string
  payload: string
}

interface ChangeLocaleAction {
  type: string
  payload: LanguageEnum
}

export interface ChangeUserInfoAction {
  type: string
  payload: UserInfoResponse
}

export interface ChangeUrlAction {
  type: string
  payload: FrontEndUrl
}

const slice = createSlice({
  initialState,
  name: 'user',
  reducers: {
    changeToken(state, action: ChangeTokenAction) {
      const token = action.payload || ''
      state.token = token
      setToken(token)
    },
    changeLanguage(state, action: ChangeLocaleAction) {
      const language = action.payload
      setLanguage(language)
      state.language = language
    },

    changeFrontEndUrl(state, action: ChangeUrlAction) {
      const { managementFrontUrl, employeeFrontUrl } = action.payload || {}

      state.managementFrontUrl = managementFrontUrl || ''
      state.employeeFrontUrl = employeeFrontUrl || ''
    },

    changeUserInfo(state, action: ChangeUserInfoAction) {
      const { resourceList, userInfo, roleList, orgList } = action.payload
      const language = userInfo?.preferredLanguage || LanguageEnum.AR
      setLanguage(language)
      state.language = language
      state.userRoleMenuList = (resourceList || []).filter(
        (v) => v.level !== RoleMenuLevel.btnMenu,
      )
      state.userRoleBtnMenuList = (resourceList || [])
        .filter((v) => v.level === RoleMenuLevel.btnMenu)
        .map((v) => v.menuCode)

      state.userInfo = userInfo
      state.roleInfo = roleList
      state.orgList = orgList
    },
  },
  extraReducers: (builder) => {
    // builder
    //   .addCase(userLogin.pending, (state, action) => {
    //     state.loading = true
    //   })
    //   .addCase(userLogin.fulfilled, (state, action) => {
    //     const { token } = action.payload || { token: null }
    //     state.token = token
    //     setToken(token || '')
    //     state.loading = false
    //   })
    //   .addCase(userLogin.rejected, (state, action) => {
    //     state.loading = false
    //   })
  },
})

export const {
  changeToken,
  changeLanguage,
  changeUserInfo,
  changeFrontEndUrl,
} = slice.actions

export default slice.reducer

const CONTRACTOR_TOKEN_KEY = 'contractor_access_token'
export const CONTRACTOR_TOKEN_CLEARED_EVENT = 'contractor-token-cleared'

export const contractorAuthStorage = {
  getToken: () => localStorage.getItem(CONTRACTOR_TOKEN_KEY),
  setToken: (token: string) => localStorage.setItem(CONTRACTOR_TOKEN_KEY, token),
  clearToken: () => {
    localStorage.removeItem(CONTRACTOR_TOKEN_KEY)
    window.dispatchEvent(new Event(CONTRACTOR_TOKEN_CLEARED_EVENT))
  },
}

