import { useMemo } from 'react'
import enUS from '@arco-design/web-react/es/locale/en-US'
import arEG from '@arco-design/web-react/es/locale/ar-EG' // 阿拉伯语（埃及）
import { isI18nArabicWeekDaysAbbreviation } from '@common/constants/env'

const WEEK_DAYS_SHORT = {
  monday: 'ن',
  tuesday: 'ث',
  wednesday: 'ر',
  thursday: 'خ',
  friday: 'ج',
  saturday: 'س',
  sunday: 'ح',
}

const WEEK_DAYS_FULL = {
  monday: 'الإثنين',
  tuesday: 'الثلاثاء',
  wednesday: 'الأربعاء',
  thursday: 'الخميس',
  friday: 'الجمعة',
  saturday: 'السبت',
  sunday: 'الأحد ',
}

const customLocaleAR = (locale: any) => {
  if (!isI18nArabicWeekDaysAbbreviation) return locale

  const short = isI18nArabicWeekDaysAbbreviation
    ? WEEK_DAYS_SHORT
    : WEEK_DAYS_FULL

  const Calendar = {
    ...locale.Calendar,
    week: {
      ...locale.Calendar.week,
      short: {
        ...locale.Calendar.week.short,
        ...short,
      },
    },
  }

  const DatePicker = {
    ...locale.DatePicker,
    Calendar: {
      ...locale.DatePicker.Calendar,
      week: {
        ...locale.DatePicker.Calendar.week,
        short: {
          ...locale.DatePicker.Calendar.week.short,
          ...short,
        },
      },
    },
  }

  return { ...locale, Calendar, DatePicker }
}

const useLocales = () => {
  return useMemo(() => {
    return { enUS, arEG: customLocaleAR(arEG) }
  }, [])
}

