import { Provider, useSelector } from 'react-redux'
import { I18nextProvider } from 'react-i18next'
import { ConfigProvider } from '@arco-design/web-react'
import { useEffect, useState } from 'react'

import '@arco-design/web-react/dist/css/arco.css'
import { useLocales } from '@common/hooks/useLocales'

import { RootState, store, persistor } from './store'
import RouterContainer from './routes'
import i18n from './locale'
import NoData from '@common/components/NoData'
import { UserState } from '@common/store/slices/user'
import { LanguageEnum } from '@common/constants/language'
import { PersistGate } from 'redux-persist/integration/react'

const App = () => {
  const { enUS, arEG } = useLocales()
  const [currentLocale, setCurrentLocale] = useState<any>(enUS)
  const { language } = useSelector<RootState, UserState>((state) => state.user)

  useEffect(() => {
    if (language === LanguageEnum.AR) {
      document.documentElement.lang = 'ar'
      document.body.dir = 'rtl'
      setCurrentLocale(arEG)
    } else {
      document.documentElement.lang = 'en'
      document.body.dir = 'ltr'
      setCurrentLocale(enUS)
    }
    i18n.changeLanguage(language)
  }, [language, enUS, arEG])

  return (
    <ConfigProvider
      locale={currentLocale}
      rtl={language === LanguageEnum.AR}
      renderEmpty={() => <NoData />}
    >
      <I18nextProvider i18n={i18n}>
        <RouterContainer />
      </I18nextProvider>
    </ConfigProvider>
  )
}

function Root() {
  return (
    <Provider store={store}>
      <PersistGate persistor={persistor}>
        <App />
      </PersistGate>
    </Provider>
  )
}

export default Root

