import { Button, Form, Input, Message } from '@arco-design/web-react'
import { useRequest } from 'ahooks'
import { useNavigate } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { appThemeName } from '@common/constants/env'
import { AppThemeName } from '@common/constants/app'
import IconOrga from '@common/assets/images/logo/orga-logo.svg?react'
import IconOrgu from '@common/assets/images/logo/logo.orgu.svg?react'
import { sendResetPasswordEmail } from '@/service'
import { encode } from '@common/utils/crypto'
import './LoginForm.less'

const FormItem = Form.Item
const classPrefix = 'contractor-login'

const ForgotPasswordForm = () => {
  const { t } = useTranslation(['common', 'contractorLogin'])
  const [form] = Form.useForm()
  const navigate = useNavigate()

  const { loading, run: sendResetLink } = useRequest(sendResetPasswordEmail, {
    manual: true,
    onSuccess() {
      Message.success(t('contractorLogin:forgot.successMsg'))
    },
    onError(e: any) {
      form.setFields({
        mail: {
          error: { message: e.message || t('contractorLogin:forgot.errorMsg') },
        },
      })
    },
  })

  const handleSubmit = (values: { mail: string }) => {
    sendResetLink({ mail: encode(values?.mail, 'verify') })
  }

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__card`}>
        <h1 className={`${classPrefix}__title`}>
          {t('contractorLogin:forgot.title')}
        </h1>
        <p className={`${classPrefix}__subtitle`}>
          {t('contractorLogin:forgot.subtitle')}
        </p>
        <Form
          form={form}
          autoComplete='off'
          layout='vertical'
          size='large'
          onSubmit={handleSubmit}
        >
          <FormItem
            label={t('contractorLogin:form.email')}
            field='mail'
            rules={[{ required: true, message: t('contractorLogin:form.emailRequired') }]}
          >
            <Input placeholder={t('contractorLogin:form.placeholder')} />
          </FormItem>
          <FormItem className={`${classPrefix}__btn-item`}>
            <div className={`${classPrefix}__btn-row`}>
              <Button
                type='outline'
                long
                onClick={() => navigate('/contractor-login')}
              >
                {t('contractorLogin:forgot.backToLogin')}
              </Button>
              <Button type='primary' htmlType='submit' long loading={loading}>
                {t('common:btn.confirm')}
              </Button>
            </div>
          </FormItem>
        </Form>
      </div>
      <div className={`${classPrefix}__logo`}>
        {appThemeName === AppThemeName.OrgA ? <IconOrga /> : <IconOrgu />}
      </div>
    </div>
  )
}

export default ForgotPasswordForm

import { useEffect, useState } from 'react'
import { Button } from '@arco-design/web-react'
import { useNavigate } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { appThemeName } from '@common/constants/env'
import { AppThemeName } from '@common/constants/app'
import IconOrga from '@common/assets/images/logo/orga-logo.svg?react'
import IconOrgu from '@common/assets/images/logo/logo.orgu.svg?react'
import './LoginForm.less'

const classPrefix = 'contractor-login'
const REDIRECT_SECONDS = 10

const PasswordSuccessIllustration = () => (
  <svg width="120" height="100" viewBox="0 0 120 100" fill="none" xmlns="http://www.w3.org/2000/svg">
    <rect x="10" y="10" width="85" height="65" rx="6" fill="#D9DDE3" />
    <rect x="10" y="10" width="85" height="65" rx="6" stroke="#C2C7CF" strokeWidth="1" />
    <circle cx="32" cy="32" r="10" fill="#B0B8C4" />
    <rect x="48" y="26" width="32" height="4" rx="2" fill="#9AA3AE" />
    <rect x="48" y="34" width="24" height="4" rx="2" fill="#9AA3AE" />
    <rect x="20" y="52" width="60" height="4" rx="2" fill="#9AA3AE" />
    <rect x="20" y="62" width="40" height="4" rx="2" fill="#9AA3AE" />
    <circle cx="82" cy="68" r="18" fill="#00B42A" />
    <path d="M73 68L79 74L91 62" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
)

const ResetPasswordSuccessView = () => {
  const { t } = useTranslation(['common', 'contractorLogin'])
  const navigate = useNavigate()
  const [countdown, setCountdown] = useState(REDIRECT_SECONDS)

  useEffect(() => {
    const timer = setInterval(() => {
      setCountdown((prev) => {
        if (prev <= 1) {
          clearInterval(timer)
          navigate('/contractor-login')
          return 0
        }
        return prev - 1
      })
    }, 1000)
    return () => clearInterval(timer)
  }, [navigate])

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__success-content`}>
        <PasswordSuccessIllustration />
        <h1 className={`${classPrefix}__success-title`}>
          {t('contractorLogin:success.title')}
        </h1>
        <Button
          type='primary'
          className={`${classPrefix}__success-btn`}
          onClick={() => navigate('/contractor-login')}
        >
          {t('contractorLogin:success.backBtn', { countdown })}
        </Button>
      </div>
      <div className={`${classPrefix}__logo`}>
        {appThemeName === AppThemeName.OrgA ? <IconOrga /> : <IconOrgu />}
      </div>
    </div>
  )
}

export default ResetPasswordSuccessView

import { Button, Form, Input, Message, Tooltip } from '@arco-design/web-react'
import { IconQuestionCircle } from '@arco-design/web-react/icon'
import { useRequest } from 'ahooks'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { appThemeName } from '@common/constants/env'
import { AppThemeName } from '@common/constants/app'
import IconOrga from '@common/assets/images/logo/orga-logo.svg?react'
import IconOrgu from '@common/assets/images/logo/logo.orgu.svg?react'
import { contractorResetPassword } from '@/service'
import { encode } from '@common/utils/crypto'
import './LoginForm.less'

const FormItem = Form.Item
const classPrefix = 'contractor-login'

const PASSWORD_SPECIAL_CHARS = '~_!@#$%^&*'
const PASSWORD_REGEX_SPECIAL = /[~_!@#$%^&*]/

const ResetPasswordForm = () => {
  const { t } = useTranslation(['common', 'contractorLogin'])
  const [form] = Form.useForm()
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const token = searchParams.get('token') || searchParams.get('resetToken') || ''

  const validatePassword = (value: string, callback: (msg?: string) => void) => {
    if (!value) return callback(t('contractorLogin:reset.validation.required'))
    if (value.length < 8 || value.length > 16)
      return callback(t('contractorLogin:reset.validation.length'))
    if (!/[A-Z]/.test(value))
      return callback(t('contractorLogin:reset.validation.uppercase'))
    if (!/[0-9]/.test(value))
      return callback(t('contractorLogin:reset.validation.number'))
    if (!PASSWORD_REGEX_SPECIAL.test(value))
      return callback(t('contractorLogin:reset.validation.special', { chars: PASSWORD_SPECIAL_CHARS }))
    if (/\s/.test(value))
      return callback(t('contractorLogin:reset.validation.noSpaces'))
    callback()
  }

  const passwordTooltipContent = (
    <ul style={{ margin: 0, paddingLeft: 16, fontSize: 12, lineHeight: 1.8 }}>
      <li>{t('contractorLogin:reset.passwordHint.length')}</li>
      <li>
        {t('contractorLogin:reset.passwordHint.complexity', { chars: PASSWORD_SPECIAL_CHARS })}
      </li>
      <li>{t('contractorLogin:reset.passwordHint.noSpaces')}</li>
    </ul>
  )

  const newPasswordLabel = (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
      {t('contractorLogin:form.newPassword')}
      <Tooltip content={passwordTooltipContent} position='top'>
        <IconQuestionCircle
          style={{ color: '#86909c', cursor: 'pointer', fontSize: 14 }}
        />
      </Tooltip>
    </span>
  )

  const { loading, run: resetPassword } = useRequest(contractorResetPassword, {
    manual: true,
    onSuccess() {
      Message.success(t('contractorLogin:reset.successMsg'))
      navigate('/contractor-login/reset-password-success')
    },
    onError(e: any) {
      Message.error(e.message || t('contractorLogin:reset.errorMsg'))
    },
  })

  const handleSubmit = (values: {
    newPassword: string
    confirmPassword: string
  }) => {
    resetPassword({
      password: encode(values.newPassword, 'verify'),
      resetToken: token,
    })
  }

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__card`}>
        <h1 className={`${classPrefix}__title`}>
          {t('contractorLogin:reset.title')}
        </h1>
        <p className={`${classPrefix}__subtitle`}>
          {t('contractorLogin:reset.subtitle')}
        </p>
        <Form
          form={form}
          autoComplete='off'
          layout='vertical'
          size='large'
          onSubmit={handleSubmit}
        >
          <FormItem
            label={newPasswordLabel}
            field='newPassword'
            rules={[
              {
                validator: (value, callback) =>
                  validatePassword(value, callback),
              },
            ]}
          >
            <Input.Password placeholder={t('contractorLogin:form.placeholder')} />
          </FormItem>
          <FormItem
            className={`${classPrefix}__password-item`}
            label={t('contractorLogin:form.confirmPassword')}
            field='confirmPassword'
            rules={[
              { required: true, message: t('contractorLogin:form.confirmPasswordRequired') },
              {
                validator: (value, callback) => {
                  if (value !== form.getFieldValue('newPassword')) {
                    callback(t('contractorLogin:form.passwordMismatch'))
                  } else {
                    callback()
                  }
                },
              },
            ]}
          >
            <Input.Password placeholder={t('contractorLogin:form.placeholder')} />
          </FormItem>
          <FormItem className={`${classPrefix}__btn-item`}>
            <Button type='primary' htmlType='submit' long loading={loading}>
              {t('contractorLogin:reset.submitBtn')}
            </Button>
          </FormItem>
        </Form>
      </div>
      <div className={`${classPrefix}__logo`}>
        {appThemeName === AppThemeName.OrgA ? <IconOrga /> : <IconOrgu />}
      </div>
    </div>
  )
}

export default ResetPasswordForm

