.contractor-header {
  background: @color-header;
  box-sizing: border-box;
  display: flex;
  flex-direction: row;

  &--left {
    display: flex;
    flex-direction: row;
    flex: 1;
    overflow: hidden;
  }

  &--right {
    display: flex;
    flex-direction: row;
  }

  &__h1 {
    margin: 0;
    display: flex;
    flex-direction: row;
    flex: 1;
    overflow: hidden;
    align-items: center;
    height: @header-height;
    padding: 12px 20px;
    box-sizing: border-box;

    &--logo {
      min-width: 150px;
      min-height: 38px;
      width: 150px;
      height: 38px;
      display: block;
    }

    &--line {
      margin: 0 16px;
      width: 1px;
      height: 16px;
      background-color: #fff;

      .is-orgu-theme & {
        background-color: #86909c;
      }
    }

    &--text {
      color: #fff;

      .is-orgu-theme & {
        color: #1d2129;
      }

      font-size: 22px;
      font-weight: @font-weight-medium;
      text-transform: uppercase;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
  }

  &__btn {
    padding: 12px 20px;
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: center;

    &--lng {
      font-size: 12px;
      font-weight: @font-weight-medium;
      display: flex;
      justify-content: center;
      align-items: center;

      html[lang='ar'] & {
        font-size: 14px;
      }

      &.arco-btn-shape-circle {
        background-color: rgba(255, 255, 255, 0.6);

        .is-orga-theme &,
        .is-orgu-theme & {
          background-color: @color-special;

          &:hover {
            background-color: @color-hover;
          }
        }

        .is-orgu-theme & {
          svg path {
            fill: @color-press;
          }
        }
      }

      &.btn-locale {
        svg {
          font-size: 30px;
        }
      }
    }
  }

  &__user-info {
    padding: 10px 12px 12px;
    background: #ffffff;
    box-shadow: 0px 4px 10px rgba(0, 0, 0, 0.1);
    border-radius: 4px;

    &__item {
      padding-top: 8px;

      &__name {
        font-style: normal;
        font-weight: @font-weight-medium;
        font-size: 16px;
        line-height: 20px;
        text-transform: capitalize;
        text-wrap: wrap;
        max-width: 190px;

        html[lang='ar'] & {
          font-weight: @font-weight-medium;
          font-size: 18px;
        }
      }

      &__tags {
        max-width: 190px;
