import { useState } from 'react'
import { Button, Form, Input } from '@arco-design/web-react'
import { useRequest, useCountDown } from 'ahooks'
import { useNavigate } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { encode } from '@common/utils/crypto'
import { contractorLogin } from '@/service'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { appThemeName } from '@common/constants/env'
import { AppThemeName } from '@common/constants/app'
import IconOrga from '@common/assets/images/logo/orga-logo.svg?react'
import IconOrgu from '@common/assets/images/logo/logo.orgu.svg?react'
import { contractorAuthStorage } from '@/pages/Contractor/contractorAuth'
import { AppDispatch } from '@/store'
import { useDispatch } from 'react-redux'
import { changeToken } from '@common/store/slices/user'
import './LoginForm.less'

const FormItem = Form.Item
const classPrefix = 'contractor-login'

const LoginForm = () => {
  const { t } = useTranslation(['common', 'contractorLogin'])
  const [form] = Form.useForm()
  const navigate = useNavigate()
  const dispatch = useDispatch<AppDispatch>()
  const LOGIN_COOLDOWN_SECONDS = 1000 * 60
  const [targetDate, setTargetDate] = useState<number>()
  const [isShowTryLaterMsg, setIsShowTryLaterMsg] = useState(false)
  const [countDown] = useCountDown({
    targetDate,
    onEnd: () => {
      setTargetDate(undefined)
      setIsShowTryLaterMsg(false)
    },
  })

  const debouncedLogin = useDebouncedPromise(contractorLogin, 500)

  const { loading, run: checkCode } = useRequest(debouncedLogin, {
    manual: true,
    onSuccess(data) {
      contractorAuthStorage.setToken(data.token)
      navigate('/contractor/list')
    },
    onError(e: any) {
      if (e?.errorCode === '40101') {
        setTargetDate(Date.now() + LOGIN_COOLDOWN_SECONDS)
        setIsShowTryLaterMsg(true)
      } else {
        setIsShowTryLaterMsg(false)
        form.setFields({
          password: {
            error: { message: e.message || '' },
          },
        })
      }
    },
  })

  const handleSubmit = (values: any) => {
    checkCode({
      mail: encode(values.mail, 'verify'),
      password: encode(values.password, 'verify'),
    })
  }

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__card`}>
        <h1 className={`${classPrefix}__title`}>
          {t('contractorLogin:login.title')}
        </h1>
        <p className={`${classPrefix}__subtitle`}>
          {t('contractorLogin:login.subtitle')}
        </p>
        <Form
          form={form}
          autoComplete='off'
          layout='vertical'
          size='large'
          onSubmit={handleSubmit}
        >
          <FormItem
            label={t('contractorLogin:form.email')}
            field='mail'
            rules={[{ required: true, message: t('contractorLogin:form.emailRequired') }]}
          >
            <Input placeholder={t('contractorLogin:form.placeholder')} />
          </FormItem>
          <FormItem
            className={`${classPrefix}__password-item`}
            label={t('contractorLogin:form.password')}
            field='password'
            rules={[{ required: true, message: t('contractorLogin:form.passwordRequired') }]}
          >
            <Input.Password placeholder={t('contractorLogin:form.placeholder')} />
          </FormItem>
          {isShowTryLaterMsg && (
            <div className={`${classPrefix}__cooldown`}>
              {t('contractorLogin:login.cooldown', { seconds: Math.round(countDown / 1000) })}
            </div>
          )}
          <button
            className={`${classPrefix}__forgot-link`}
            type='button'
            onClick={() =>
              navigate('/contractor-login/reset-password-sendEmail')
            }
          >
            {t('contractorLogin:login.forgotPassword')}
          </button>
          <FormItem className={`${classPrefix}__btn-item`}>
            <Button
              type='primary'
              htmlType='submit'
              long
              loading={loading}
              disabled={isShowTryLaterMsg}
            >
              {t('contractorLogin:login.signIn')}
            </Button>
          </FormItem>
        </Form>
      </div>
      <div className={`${classPrefix}__logo`}>
        {appThemeName === AppThemeName.OrgA ? <IconOrga /> : <IconOrgu />}
      </div>
    </div>
  )
}

export default LoginForm

