input.content:
.contractor-login {
  width: 100%;
  min-height: 100vh;
  background-color: #f0f2f5;
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 10px 20px;
  box-sizing: border-box;

  &__card {
    background: #fff;
    border-radius: 12px;
    border: 1px solid #e5e6eb;
    padding: 28px 36px;
    width: 100%;
    max-width: 480px;
    min-height: 380px;
    box-sizing: border-box;
  }

  &__title {
    font-size: 26px;
    font-weight: 600;
    color: #1d2129;
    margin: 0 0 12px;
    line-height: 1.4;
    text-align: left;
  }

  &__subtitle {
    font-size: 14px;
    color: #86909c;
    margin: 0 0 28px;
    line-height: 1.6;
    text-align: left;
  }

  &__password-item {
    margin-top: 16px;

    .arco-input-inner-wrapper {
      padding: 0;

      input {
        padding-left: 16px;
        padding-right: 16px;
      }

      span {
        position: absolute;
        right: 9px;
      }
    }
  }

  &__btn-item {
    margin-top: 32px !important;

    .arco-btn {
      height: 44px;
      font-size: 15px;
      border-radius: 6px;
    }
  }

  &__btn-row {
    display: flex;
    gap: 16px;

    .arco-btn {
      flex: 1;
    }
  }

  &__hint {
    text-align: center;
    color: #86909c;
    font-size: 13px;
    margin: 8px 0 0;
    line-height: 1.5;
  }

  &__cooldown {
    color: rgb(var(--danger-6));
    font-size: 12px;
    margin-top: -4px;
    margin-bottom: 4px;
    text-align: left;
  }

  &__logo {
    margin-top: 32px;
    svg {
      width: 200px;
      height: 40px;
    }
  }

  .arco-input-inner-wrapper {
    &:has(input:-webkit-autofill) {
      &,
      &:hover {
        background-color: rgb(232, 240, 254);
      }
    }

    input:-webkit-autofill {
      background-color: rgb(232, 240, 254);
    }
  }

  .arco-form-item-feedback {
    display: flex;
  }

  &__forgot-link {
    display: block;
    text-align: right;
    color: #30647f;
    font-size: 13px;
    background: none;
    border: none;
    padding: 0;
    margin-top: -8px;
    margin-bottom: 24px;
    cursor: pointer;

    &:hover {
      color: #1a6f8a;
      text-decoration: underline;
    }
  }

  &__back-link {
    display: block;
    text-align: center;
    color: #86909c;
    font-size: 13px;
    background: none;
    border: none;
    padding: 0;
    margin-top: 16px;
    cursor: pointer;
    width: 100%;

    &:hover {
      color: #30647f;
    }
  }

  &__status-icon {
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 24px;

    .arco-icon {
      font-size: 56px;
    }

    &--mail .arco-icon {
      color: #30647f;
    }

    &--success .arco-icon {
      color: #00b42a;
    }
  }

  &__card--icon-page {
    height: auto;
    min-height: 380px;
    text-align: center;

    .arco-form-item {
      text-align: left;
    }
  }

  &__success-content {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 0;
  }

  &__success-title {
    font-size: 22px;
    font-weight: 600;
    color: #1d2129;
    text-align: center;
    margin: 24px 0 32px;
    line-height: 1.5;
  }

  &__success-btn {
    width: 360px;
    height: 44px;
    font-size: 15px;
    border-radius: 6px;
    background-color: #4a7c8e;
    border-color: #4a7c8e;

    &:hover,
    &:focus {
      background-color: #3d6b7d;
      border-color: #3d6b7d;
    }
  }

  &__action-btn {
    margin-top: 8px;
    width: 100%;

    .arco-btn {
      height: 44px;
      font-size: 15px;
      border-radius: 6px;
      width: 100%;
    }
  }
}

