import { useEffect, useState } from 'react'
import { Button } from '@arco-design/web-react'
import { useNavigate } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { appThemeName } from '@common/constants/env'
import { AppThemeName } from '@common/constants/app'
import IconOrga from '@common/assets/images/logo/orga-logo.svg?react'
import IconOrgu from '@common/assets/images/logo/logo.orgu.svg?react'
import './LoginForm.less'

const classPrefix = 'contractor-login'
const REDIRECT_SECONDS = 10

const PasswordSuccessIllustration = () => (
  <svg width="120" height="100" viewBox="0 0 120 100" fill="none" xmlns="http://www.w3.org/2000/svg">
    <rect x="10" y="10" width="85" height="65" rx="6" fill="#D9DDE3" />
    <rect x="10" y="10" width="85" height="65" rx="6" stroke="#C2C7CF" strokeWidth="1" />
    <circle cx="32" cy="32" r="10" fill="#B0B8C4" />
    <rect x="48" y="26" width="32" height="4" rx="2" fill="#9AA3AE" />
    <rect x="48" y="34" width="24" height="4" rx="2" fill="#9AA3AE" />
    <rect x="20" y="52" width="60" height="4" rx="2" fill="#9AA3AE" />
    <rect x="20" y="62" width="40" height="4" rx="2" fill="#9AA3AE" />
    <circle cx="82" cy="68" r="18" fill="#00B42A" />
    <path d="M73 68L79 74L91 62" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
)

const ResetPasswordSuccessView = () => {
  const { t } = useTranslation(['common', 'contractorLogin'])
  const navigate = useNavigate()
  const [countdown, setCountdown] = useState(REDIRECT_SECONDS)

  useEffect(() => {
    const timer = setInterval(() => {
      setCountdown((prev) => {
        if (prev <= 1) {
          clearInterval(timer)
          navigate('/contractor-login')
          return 0
        }
        return prev - 1
      })
    }, 1000)
    return () => clearInterval(timer)
  }, [navigate])

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__success-content`}>
        <PasswordSuccessIllustration />
        <h1 className={`${classPrefix}__success-title`}>
          {t('contractorLogin:success.title')}
        </h1>
        <Button
          type='primary'
          className={`${classPrefix}__success-btn`}
          onClick={() => navigate('/contractor-login')}
        >
          {t('contractorLogin:success.backBtn', { countdown })}
        </Button>
      </div>
      <div className={`${classPrefix}__logo`}>
        {appThemeName === AppThemeName.OrgA ? <IconOrga /> : <IconOrgu />}
      </div>
    </div>
  )
}

export default ResetPasswordSuccessView

