import DeleteConfirmModal from '@common/components/DeleteConfirmModal'
import { useRequest } from 'ahooks'
import { ContractorApproval } from '@/constants/contractor'


// status: 0=Draft 1=UnderReview 2=Approved 3=Rejected
// shift:  1=Day   2=Night

interface PatrolRecordRow {
  patrolId: number
  patrolDate: string
  shift: number
  patrollerUserId: number
  patrollerUser: string
  status: number
  answerCount: number
  issuesObserved: number
  inspector: string
  reportTime: string
  patroller: any
}

interface PatrolRecordFilters {
  status?: number
  patrolDate?: { startTime?: string; endTime?: string }
  shift?: any
  patroller?: any
}

