    display: flex;
    align-items: center;
    gap: 8px;
    padding: 9px 16px;
    font-size: 14px;
    font-weight: 500;
    color: #4e5969;
    margin-top: 4px;
    cursor: pointer;
    user-select: none;
    transition: background-color 0.15s, color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
    }
  }

  // Child nav item (floors, P1/P2/P3)
  &__nav-child {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 7px 16px 7px 32px;
    font-size: 13px;
    font-weight: 400;
    color: #4e5969;
    cursor: pointer;
    position: relative;
    user-select: none;
    transition: background-color 0.15s, color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
      background-color: #f0f7fb;
      font-weight: 500;

      &::before {
        content: '';
        position: absolute;
        left: 0;
        top: 0;
        bottom: 0;
        width: 3px;
        background-color: #30647f;
      }
    }
  }

  &__nav-label {
    flex: 1;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  // Filled dot for parent-level items
  &__nav-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: #c9cdd4;
    flex-shrink: 0;

    &--active {
      background-color: #30647f;
    }
  }

  // Hollow dot for child items
  &__nav-child-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    border: 1.5px solid #c9cdd4;
    background: transparent;
    flex-shrink: 0;

    &--active {
      border-color: #30647f;
      background-color: #30647f;
    }
  }

  // Number badge in sidebar (findings count)
  &__nav-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 20px;
    height: 18px;
    padding: 0 6px;
    border-radius: 4px;
    background-color: #ffeae8;
    color: #f5626c;
    font-size: 11px;
    font-weight: 600;
    line-height: 1;
    flex-shrink: 0;
  }

  // Green checkmark circle (shared: sidebar + other badges)
  &__badge-ok {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background-color: #00b42a;
    color: #fff;
    font-size: 10px;
    font-weight: 700;
    line-height: 1;
    flex-shrink: 0;
  }

  // ── Content area (right side) ─────────────────────────────────────────────
  &__content-area {
    flex: 1;
    overflow-y: auto;
    padding: 28px 36px;

    .arco-form {
      height: 100%;
    }
  }

  // Content header: title + subtitle + Check & Save button
  &__content-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    margin-bottom: 24px;
    gap: 16px;
  }

  &__content-title {
    font-size: 28px;
    font-weight: 600;
    color: #1d2129;
    line-height: 1.3;
    margin-bottom: 6px;
  }

  &__content-subtitle {
    font-size: 13px;
    color: #86909c;
    line-height: 1.5;
  }

  &__check-save-btn {
    flex-shrink: 0;
    background: linear-gradient(to top, #30647f, #4a8099) !important;
    border-color: transparent !important;

    &:hover {
      background: linear-gradient(to top, #265569, #3d7088) !important;
    }
  }

  // ── Section cards ─────────────────────────────────────────────────────────
  &__sections {
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  &__loading {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 80px 0;
  }

  &__section {
    border: 1px solid #e5e6eb;
    border-radius: 8px;
    overflow: hidden;

    &-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      min-height: 72px;
      padding: 12px 20px;
      background-color: #f7f8fa;
      cursor: pointer;
      user-select: none;
      transition: background-color 0.15s;

      &--open {
        border-bottom: 1px solid #e5e6eb;
      }

      &:hover {
        background-color: #f0f1f2;
      }

      .arco-icon {
        font-size: 16px;
        color: #1d2129;
        flex-shrink: 0;
      }
    }

    &-no {
      font-size: 12px;
      font-weight: 500;
      color: #30647f;
      text-transform: uppercase;
      letter-spacing: 0.3px;
      line-height: 22px;
      margin-bottom: 2px;
    }

    &-title {
      font-size: 20px;
      font-weight: 500;
      color: #1d2129;
      text-transform: uppercase;
      letter-spacing: 1px;
