  // ── Yes/No toggle ─────────────────────────────────────────────────────────
  &__yes-no {
    display: inline-flex;
    align-items: center;
    width: 240px;
    height: 36px;
    padding: 4px;
    gap: 4px;
    border-radius: 8px;
    background-color: #f7f8fa;
    overflow: hidden;

    &-btn {
      flex: 1;
      height: 100%;
      border: none;
      background: transparent;
      color: #86909c;
      font-size: 14px;
      border-radius: 4px;
      cursor: pointer;
      transition: background-color 0.15s, color 0.15s;

      &--yes-active {
        background: linear-gradient(to top, #30647f, #4a8099);
        color: #fff;
      }

      &--no-active {
        background: linear-gradient(to top, #cb3d4b, #f5626c);
        color: #fff;
      }
    }
  }

  // ── Findings wrap ─────────────────────────────────────────────────────────
  &__findings-wrap {
    margin-top: 20px;
    background-color: #f7f8fa;
    border-radius: 8px;
    padding: 12px;
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  &__findings-list {
    display: flex;
    flex-direction: column;
    gap: 16px;
  }

  &__finding-divider {
    height: 1px;
    background-color: #e5e6eb;
    flex-shrink: 0;
  }

  &__add-finding-btn {
    color: #30647f !important;
    border-color: #e5e6eb !important;
    background-color: #fff !important;
    align-self: flex-start;

    &:hover {
      color: #1a6f8a !important;
      border-color: #30647f !important;
    }
  }

  // ── Individual finding card ───────────────────────────────────────────────
  &__finding {
    &-head {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 20px;
    }

    &-title {
      font-size: 16px;
      font-weight: 500;
      color: #1d2129;
      text-transform: uppercase;
    }

    &-body {
      display: flex;
      flex-direction: column;
      gap: 20px;
    }

    &-row {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 12px;

      .arco-form-item {
        margin-bottom: 0;
      }

      .arco-form-label-item {
        margin-bottom: 6px;
      }
    }
  }

  // ── Field blocks ──────────────────────────────────────────────────────────
  &__field {
    &-block {
      .arco-form-item {
        margin-bottom: 0;
      }
    }

    &-label {
      font-size: 14px;
      color: #4e5969;
      margin-bottom: 8px;
      line-height: 22px;

      &--required::before {
        content: '* ';
        color: #f53f3f;
      }
    }
  }

  // ── Upload ────────────────────────────────────────────────────────────────
  &__upload {
    &-tip {
      font-size: 12px;
      color: #86909c;
      margin-bottom: 10px;
      line-height: 22px;
    }

    &-trigger {
      width: 64px;
      height: 64px;
      border: 1px dashed #e5e6eb;
      border-radius: 4px;
      background-color: #fff;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      color: #86909c;
      font-size: 12px;
      cursor: pointer;
      gap: 4px;
      transition: border-color 0.2s, color 0.2s;

      .arco-icon {
        font-size: 20px;
      }

      &:hover {
        border-color: #30647f;
        color: #30647f;
      }
    }
  }

  .arco-upload-trigger-picture {
    width: auto;
    height: auto;
    border: none;
    background-color: transparent;
    padding: 0;
  }

  // ── Submit confirmation modal ─────────────────────────────────────────────
  &__confirm-modal {
    display: flex;
    flex-direction: column;
    gap: 24px;
  }

  &__confirm-modal-header {
    display: flex;
    align-items: flex-start;
    gap: 16px;
  }

  &__confirm-modal-icon {
    font-size: 24px;
    color: #ff7d00;
    flex-shrink: 0;
    margin-top: 1px;
  }

  &__confirm-modal-title {
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    margin-bottom: 8px;
  }

  &__confirm-modal-desc {
    font-size: 14px;
    color: #4e5969;
    line-height: 1.5;
  }

  &__confirm-modal-field {
    padding-left: 40px;
  }

  &__confirm-modal-label {
    font-size: 14px;
    color: #4e5969;
    margin-bottom: 8px;
    line-height: 22px;
  }

  &__confirm-modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 10px;

    .arco-btn-primary {
      background: linear-gradient(to top, #30647f, #4a8099);
      border-color: transparent;

      &:hover {
        background: linear-gradient(to top, #265569, #3d7088);
      }
