  // ── Footer ────────────────────────────────────────────────────────────────
  &__footer {
    position: sticky;
    bottom: 0;
    z-index: 10;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 12px;
    padding: 16px 20px;
    background-color: #fff;
    border-top: 1px solid #e5e6eb;

    .arco-btn-primary {
      background: linear-gradient(to top, #30647f, #4a8099);
      border-color: transparent;

      &:hover {
