// ─── Types ────────────────────────────────────────────────────────────────────

type Answer = 1 | 0 | null

interface AttachmentItem {
  url: string
  absUrl?: string
  name: string
}

interface Finding {
  id: string
  notesAr: string
  notesEn: string
  attachments: AttachmentItem[]
  correctiveActionAr: string
  correctiveActionEn: string
  dept: string
  targetClosureDate: string
}

interface QuestionItem {
  id: string
  question: string
  answer: Answer
  findings: Finding[]
}

interface Section {
  id: string
  no: number
  title: string
  defaultOpen: boolean
  items: QuestionItem[]
}

const INSIDE_FLOORS = [
  { label: 'G', value: 0 },
  { label: 'M', value: 1 },
  { label: '1', value: 2 },
  { label: '2', value: 3 },
  { label: '3', value: 4 },
  { label: '4', value: 5 },
  { label: '5', value: 6 },
  { label: '6', value: 7 },
  { label: 'RF', value: 8 },
] as const
type FloorKey = (typeof INSIDE_FLOORS)[number]

const PARKING_SUBS = [
  { label: 'P1', value: 9 },
  { label: 'P2', value: 10 },
  { label: 'P3', value: 11 },
] as const
type ParkingKey = (typeof PARKING_SUBS)[number]

type NavSel =
  | { area: 'around' }
  | { area: 'inside'; floor: FloorKey }
  | { area: 'parking'; sub: ParkingKey }

// ─── Constants ────────────────────────────────────────────────────────────────

const classPrefix = 'ratrol-record-detail'

// ─── Approval mock data (右侧审批暂不对接) ────────────────────────────────────

