164	  const result: string[] = []
165	  const orgIdList = (nodes?: OrgNode[]) => {
166	    if (!Array.isArray(nodes)) return
167	    for (const node of nodes) {
168	      if (node.orgId) {
169	        result.push(String(node.orgId))
