182	  const leafKeys = []
183	  function traverseNodes(nodes) {
184	    if (!Array.isArray(nodes)) return
185	
186	    for (const node of nodes) {
187	      if (!node.children || node.children.length === 0) {
188	        // 如果没有 children 属性或 children 数组为空，则是叶子节点
189	        leafKeys.push(node.key)
190	      } else {
191	        // 如果有 children，继续递归遍历
192	        traverseNodes(node.children)
193	      }
194	    }
195	  }
196	  traverseNodes(data)
197	  return leafKeys
198	}
