295	export const checkCompletionStatusForActivityRisk = (arr) => {
296	  if (_.isEmpty(arr)) {
297	    return false
298	  } else {
299	    for (let i = 0; i < arr.length; i++) {
300	      const item = arr[i]
301	      // check recordRiskDetailBOList every object has completionStatus not equal 1
302	      if (!_.isEmpty(item.recordRiskDetailBOList)) {
303	        for (let j = 0; j < item.recordRiskDetailBOList.length; j++) {
304	          if (item.recordRiskDetailBOList[j].completionStatus !== 1) {
305	            return false
306	          }
307	        }
308	      }
309	    }
310	  }
311	
312	  return true
313	}
