import { saveAs } from 'file-saver'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import _ from 'lodash'
import { CurrentUserInfo } from '@common/types/user'

export function isOverThreeLines(text, fontSize, containerWidth) {
  // 创建一个隐藏的DOM元素来测量
  const measureElement = document.createElement('div')
  measureElement.style.position = 'absolute'
  measureElement.style.whiteSpace = 'pre-wrap' // 保留空格和换行
  measureElement.style.wordWrap = 'break-word' // 让长单词也能换行
  measureElement.style.visibility = 'hidden' // 隐藏元素
  measureElement.style.fontSize = `${fontSize}px` // 设置字号
  measureElement.style.width = `${containerWidth}px` // 设置容器宽度
  measureElement.textContent = text // 放入待测文本
  document.body.appendChild(measureElement) // 将测量元素加入到DOM

  // 计算行数
  const lineCount = measureElement.scrollHeight / measureElement.offsetHeight

  document.body.removeChild(measureElement) // 测量完移除元素

  return lineCount > 3 // 返回是否超过三行
}

export function downloadFile(data, fileName) {
  saveAs(new Blob([data], { type: 'application/octet-stream' }), fileName)
}

export const setFavicon = (env: string): void => {
  if (!document || !document.head) {
    console.error('Document or head element not available')
    return
  }
  const faviconUrl: string = `/favicon-${env}.svg`
  const existingLink = document.querySelector(
    "link[rel~='icon']",
  ) as HTMLLinkElement | null
  const link: HTMLLinkElement = existingLink
    ? existingLink
    : document.createElement('link')

  link.rel = 'icon'
  link.href = faviconUrl
  if (!existingLink) {
    document.head.appendChild(link)
  }
}

interface TransformedNode {
  title: string
  key: string
  children?: TransformedNode[]
}

export interface TransformedOrgNode {
  title: string
  key: string
  disabled: boolean
  children?: TransformedOrgNode[]
}

interface OrgNode {
  id: string
  orgId: string
  parentId: string
  orgName: string
  orgNameAr: string
  head: null | any
  children?: OrgNode[]
}

export function transformData(data: OrgNode[]): TransformedOrgNode[] {
  // 递归转换函数
  const transformNode = (node): TransformedOrgNode => {
    const transformed: TransformedOrgNode = {
      title: handelFieldNameShow(node.orgName, node.orgNameAr),
      key: node.orgId, //orgId
      disabled: node.activeFlag === 0,
    }
    // 只有当有children时才添加children属性
    if (Array.isArray(node.children) && node.children.length > 0) {
      transformed.children = node.children.map(transformNode)
    }
    return transformed
  }
  // 处理整个数据数组
  return data?.map(transformNode)
}

export function getMatchedUserOrgId(
  data: OrgNode[],
  userInfo?: Partial<CurrentUserInfo>,
) {
  const targetOrgIds = [userInfo?.belongDeptId, userInfo?.belongEntityId]
    .filter(Boolean)
    .map((item) => String(item))

  if (_.isEmpty(targetOrgIds)) {
    return undefined
  }

  const findOrgId = (nodes?: OrgNode[]): string | undefined => {
    if (!Array.isArray(nodes)) {
      return undefined
    }

    for (const node of nodes) {
      if (targetOrgIds.includes(String(node.orgId))) {
        return String(node.orgId)
      }

      const childMatchedOrgId = findOrgId(node.children)
      if (childMatchedOrgId) {
        return childMatchedOrgId
      }
    }

    return undefined
  }

  return findOrgId(data)
}

export function transformRelatedActivity(
  data: OrgNode[],
  disableRootSelectable: boolean = false,
): TransformedNode[] {
  // 递归转换函数
  const transformNode = (node): TransformedNode => {
    const transformed: TransformedNode = {
      title: handelFieldNameShow(node.recordName, node.recordNameAr),
      key: node.recordId, //orgId
      ...(disableRootSelectable ? { disabled: true } : {}),
    }
    transformed.children = node.activities.map((item) => ({
      title: handelFieldNameShow(item.activityName, item.activityNameAr),
      key: item.activityId,
    }))
    return transformed
  }
  // 处理整个数据数组
  return data?.map(transformNode)
}

export function changeDateFormatToShow(date) {
  return _.isEmpty(date) ? '' : date.split('/').join('-')
}

export function changeDateFormatToParams(date) {
  return date.split('-').join('/')
}

export function changeDateFormatToComparison(date) {
  if (date.includes('-')) {
    return date.split('-').reverse().join('-')
  } else if (date.includes('/')) {
    return date.split('/').reverse().join('/')
  }
}
// 递归遍历部门树 获取所有orgId
export const collectAllOrgIds = (data: OrgNode[]): string[] => {
  const result: string[] = []
  const orgIdList = (nodes?: OrgNode[]) => {
    if (!Array.isArray(nodes)) return
    for (const node of nodes) {
      if (node.orgId) {
        result.push(String(node.orgId))
      }
      if (Array.isArray(node.children) && node.children.length > 0) {
        orgIdList(node.children)
      }
    }
  }
  orgIdList(data)
  return result
}

// get department tree leaf node
export const getAllLeafKeys = (data) => {
  const leafKeys = []
  function traverseNodes(nodes) {
    if (!Array.isArray(nodes)) return

    for (const node of nodes) {
      if (!node.children || node.children.length === 0) {
        // 如果没有 children 属性或 children 数组为空，则是叶子节点
        leafKeys.push(node.key)
      } else {
        // 如果有 children，继续递归遍历
        traverseNodes(node.children)
      }
    }
  }
  traverseNodes(data)
  return leafKeys
}
export const truncateString = (str: string, maxLength: number) => {
  if (str.length <= maxLength) {
    return str
  }
  return str.slice(0, maxLength - 3) + '...'
}

export const handelFieldNameShow = (nameEn: string, nameAr: string) => {
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  return isLanguageAR ? nameAr : _.isEmpty(nameEn) ? nameAr : nameEn
}

//get all exchange label
export const getLabelsByValues = (values, options) => {
  return options
    .filter((option) => values?.includes(String(option.value)))
    .map((option) => option.label)
    .join(',')
}

//直接调用后端接口数据不做前端处理的部门
//activeFlag == 0 不可点击  activeFlag == 1 可点击
export function orgTransformData(data: OrgNode[]): TransformedOrgNode[] {
  // 递归转换函数
  const transformNode = (node): TransformedOrgNode => {
    const transformed: TransformedOrgNode = {
      title: handelFieldNameShow(node.orgName, node.orgNameAr),
      key: node.orgId,
      disabled: node.activeFlag === 0,
    }
    if (Array.isArray(node.children) && node.children.length > 0) {
      transformed.children = node.children.map(transformNode)
    }
    return transformed
  }
  // 处理整个数据数组
  return data?.map(transformNode)
}

/**
 * 根据 riskName 过滤 riskDetailActivityBOList 数据
 * @param {Array} dataList - 原始数据列表
 * @param {string} riskName - 要过滤的 riskName
 * @returns {Array} 过滤后的数据列表
 */
export const filterByRiskId = (dataList, riskName) => {
  if (!Array.isArray(dataList) || !riskName) {
    return []
  }

  return dataList
    .filter((activity) => {
      // 检查 recordRiskDetailBOList 中是否包含指定的 riskId
      const hasRiskInDetails = activity.recordRiskDetailBOList?.some(
        (risk) => risk.nameAr === riskName || risk.name === riskName,
      )

      // 检查 recordRiskProceduresBOList 中是否包含指定的 riskId
      const hasRiskInProcedures = activity.recordRiskProceduresBOList?.some(
        (procedure) =>
          procedure.riskNameAr === riskName || procedure.riskName === riskName,
      )

      return hasRiskInDetails || hasRiskInProcedures
    })
    .map((activity) => {
      // 创建深拷贝以避免修改原数据
      const filteredActivity = { ...activity }

      // 过滤 recordRiskDetailBOList
      if (filteredActivity.recordRiskDetailBOList) {
        filteredActivity.recordRiskDetailBOList =
          filteredActivity.recordRiskDetailBOList.filter(
            (risk) => risk.nameAr === riskName || risk.name === riskName,
          )
      }

      // 过滤 recordRiskProceduresBOList
      if (filteredActivity.recordRiskProceduresBOList) {
        filteredActivity.recordRiskProceduresBOList =
          filteredActivity.recordRiskProceduresBOList.filter(
            (procedure) =>
              procedure.riskNameAr === riskName ||
              procedure.riskName === riskName,
          )
      }

      return filteredActivity
    })
}

//check all completion status
export const checkAllCompletionStatus = (arr) => {
  return arr.every((item) => item.completionStatus === 1)
}

export const checkCompletionStatusForActivityRisk = (arr) => {
  if (_.isEmpty(arr)) {
    return false
  } else {
    for (let i = 0; i < arr.length; i++) {
      const item = arr[i]
      // check recordRiskDetailBOList every object has completionStatus not equal 1
      if (!_.isEmpty(item.recordRiskDetailBOList)) {
        for (let j = 0; j < item.recordRiskDetailBOList.length; j++) {
          if (item.recordRiskDetailBOList[j].completionStatus !== 1) {
            return false
          }
        }
      }
    }
  }

  return true
}

