        font-size: 20px;
      }

      &:hover {
        border-color: #30647f;
        color: #30647f;
      }
    }
  }

  .arco-upload-trigger-picture {
    width: auto;
    height: auto;
    border: none;
    background-color: transparent;
    padding: 0;
  }

  // ── Submit confirmation modal ─────────────────────────────────────────────
  &__confirm-modal {
    display: flex;
    flex-direction: column;
    gap: 24px;
  }

  &__confirm-modal-header {
    display: flex;
