    border-radius: 12px;
    box-shadow: 0 4px 8px 0 rgba(0, 0, 0, 0.05);
    overflow: clip;
  }

  // ── Card header ───────────────────────────────────────────────────────────
  &__card-header {
    flex-shrink: 0;
    display: flex;
    align-items: center;
