  // ── Meta bar ──────────────────────────────────────────────────────────────
  &__meta-bar {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    gap: 36px;
    padding: 12px 20px;
    background-color: #f7f8fa;
    border-bottom: 1px solid #e5e6eb;
  }

  &__meta-item {
    display: flex;
    align-items: center;
    gap: 8px;
  }

  &__meta-label {
    font-size: 13px;
    color: #86909c;
    white-space: nowrap;
