    padding: 7px 16px 7px 32px;
    font-size: 13px;
    font-weight: 400;
    color: #4e5969;
    cursor: pointer;
    position: relative;
    user-select: none;
    transition: background-color 0.15s, color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
      background-color: #f0f7fb;
      font-weight: 500;

      &::before {
        content: '';
        position: absolute;
        left: 0;
        top: 0;
        bottom: 0;
        width: 3px;
        background-color: #30647f;
      }
    }
  }

  &__nav-label {
